import redis
import json

class AdvancedCacheClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db, decode_responses=True)
    
    def execute_lua_script(self, lua_script, keys=None, args=None):
        """
        Execute Lua script with dynamic cache operations
        
        Args:
            lua_script (str): Lua script code
            keys (list): Redis key names to use in script
            args (list): Arguments to pass to the script
        
        Returns:
            Result of Lua script execution
        """
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        try:
            result = self.redis_client.eval(lua_script, len(keys), *keys, *args)
            return result
        except Exception as e:
            print(f"Error executing Lua script: {e}")
            return None
    
    def cache_set_with_ttl(self, key, value, ttl_seconds):
        """Set cache with TTL using Lua script"""
        lua_script = """
        redis.call('SET', KEYS[1], ARGV[1])
        redis.call('EXPIRE', KEYS[1], ARGV[2])
        return 'OK'
        """
        return self.execute_lua_script(lua_script, [key], [value, str(ttl_seconds)])
    
    def atomic_increment(self, key, increment=1):
        """Atomic increment with Lua script"""
        lua_script = """
        local current = redis.call('GET', KEYS[1])
        if current == false then
            current = 0
        else
            current = tonumber(current)
        end
        local new_value = current + tonumber(ARGV[1])
        redis.call('SET', KEYS[1], new_value)
        return new_value
        """
        return self.execute_lua_script(lua_script, [key], [str(increment)])
    
    def batch_operations(self, operations):
        """Execute multiple operations in one Lua script"""
        lua_script = """
        local results = {}
        for i, op in ipairs(ARGV) do
            local parts = {}
            for part in string.gmatch(op, "[^%s]+") do
                table.insert(parts, part)
            end
            local command = parts[1]
            if command == "SET" then
                redis.call('SET', parts[2], parts[3])
                table.insert(results, "OK")
            elseif command == "GET" then
                local value = redis.call('GET', parts[2])
                table.insert(results, value or "")
            end
        end
        return results
        """
        return self.execute_lua_script(lua_script, [], [json.dumps(operations)])

